CREATE TABLE `business_latest_summary` (
  `summary_id` bigint unsigned NOT NULL AUTO_INCREMENT COMMENT '汇总数据唯一标识',
  `session_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '关联会话ID',
